  setDoc?.getElementById('btn-theme-next')?.addEventListener('click', () => {
    audio.playButton();
    gsm.currentTheme = (gsm.currentTheme + 1) % THEMES.length;
    gsm.themesUsed.add(gsm.currentTheme);
    setText('settings', 'set-theme', THEMES[gsm.currentTheme].name);
